#[test]
fn highlight_named_palette_value_roundtrips_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:highlight w:val="darkYellow"/></w:rPr><w:t>flagged</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "darkYellow is an enumerated ST_HighlightColor value (ISO 29500-1 §17.18.40), so the package is schema-valid and Word opens it without repair (§17.3.2.15). validate() issues: {detail}"
    );
}

#[test]
fn vertalign_baseline_distinct_from_superscript() {
    let body = r#"<w:p><w:r><w:rPr><w:vertAlign w:val="baseline"/></w:rPr><w:t>level</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "baseline is a valid ST_VerticalAlignRun enumeration value (ISO 29500-1 §22.9.2.17, §17.3.2.42), so the doc opens without repair. validate() issues: {detail}"
    );
}

#[test]
fn color_and_sz_authored_order_preserved_verbatim_and_opens_clean() {
    // Authored sz-first, color-second (reverse of Annex A color(19)/sz(24)). The
    // Word oracle confirmed Word opens mis-ordered rPr children clean without
    // repair (CONFORMANCE-SWEEP-SUMMARY.md), and stemma re-zips untouched runs
    // verbatim — so the authored sz-then-color order survives the no-edit
    // roundtrip. Reordering would only run on an edit that rebuilds the run.
    let body = r#"<w:p><w:r><w:rPr><w:sz w:val="24"/><w:color w:val="FF0000"/></w:rPr><w:t>red</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);

    let sz_pos = xml.find("<w:sz");
    let color_pos = xml.find("<w:color");
    assert!(
        color_pos.is_some() && sz_pos.is_some(),
        "CT_RPr must preserve both sz and color children (ECMA-376 §17.3.2.6, §17.3.2.38). color={color_pos:?} sz={sz_pos:?}; xml: {xml}"
    );
    assert!(
        sz_pos.unwrap() < color_pos.unwrap(),
        "untouched run markup round-trips verbatim: authored sz-then-color order is preserved on the no-edit roundtrip (Word tolerates the order variance). xml: {xml}"
    );

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "Word opens mis-ordered rPr children clean (oracle-confirmed), so this round-trips schema-valid (Annex A CT_RPr). validate() issues: {detail}"
    );
}

#[test]
fn highlight_val_none_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:highlight w:val="none"/></w:rPr><w:t>Plain</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "'none' is a member of ST_HighlightColor (ISO 29500-1 §17.18.40), so the markup is schema-valid and Word opens it without repair (§17.3.2.15). validate() issues: {detail}"
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Plain",
        "highlight is a background behind the run content (§17.3.2.15), so it never contributes to or removes text; accept-all text is unchanged."
    );

    let rejected = Document::parse(&b)
        .unwrap()
        .read_rejected()
        .unwrap()
        .to_text();
    assert_eq!(
        rejected.trim(),
        "Plain",
        "No tracked change is present and highlight is render-only; reject-all text equals the original (§17.3.2.15)."
    );
}

#[test]
fn color_themecolor_supersedes_val_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:color w:val="FF0000" w:themeColor="accent3"/></w:rPr><w:t>Themed</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "color with both val and themeColor is schema-valid (ISO 29500-1 §17.3.2.6); Word opens it without repair, resolving color from the theme (MS-OI29500 §2.1.72). validate() issues: {detail}"
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Themed",
        "color (themed or literal) is render-only; per MS-OI29500 §2.1.72 the val is ignored, but neither path alters the run's text, so accept-all text equals the original (§17.3.2.6)."
    );
}

#[test]
fn underline_themecolor_supersedes_color_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:u w:val="single" w:color="4F81BD" w:themeColor="accent1"/></w:rPr><w:t>Underlined</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "u with val, color, and themeColor is schema-valid (ISO 29500-1 §17.3.2.40); Word opens it without repair (MS-OI29500 §2.1.100). validate() issues: {detail}"
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Underlined",
        "Underline (whatever color resolution wins) is decoration, not text; accept-all text equals the original run text (§17.3.2.40)."
    );
}

#[test]
fn underline_missing_val_defaults_no_underline_opens_clean() {
    let body =
        r#"<w:p><w:r><w:rPr><w:u w:color="auto"/></w:rPr><w:t>NoVal</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "u@val is optional (MS-OI29500 §2.1.100); a u element with only a color attribute is valid and Word opens it without repair (§17.3.2.40). validate() issues: {detail}"
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "NoVal",
        "With val absent Word resolves to no underline; underline presence/absence is render-only and never changes text, so accept-all text equals the original (MS-OI29500 §2.1.100)."
    );
}

#[test]
fn color_themeshade_and_themetint_both_present_opens_clean() {
    let body = r#"<w:p><w:r><w:rPr><w:color w:val="943634" w:themeColor="accent2" w:themeShade="BF" w:themeTint="99"/></w:rPr><w:t>Conflict</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "A color element bearing themeColor, themeShade, and themeTint together is schema-valid (ISO 29500-1 §17.3.2.6); Word opens it without repair and applies themeTint (MS-OI29500 §2.1.72). validate() issues: {detail}"
    );

    let accepted = Document::parse(&b)
        .unwrap()
        .read_accepted()
        .unwrap()
        .to_text();
    assert_eq!(
        accepted.trim(),
        "Conflict",
        "Color resolution (themeTint-wins) is render-only and never alters the run's text; accept-all text equals the original (MS-OI29500 §2.1.72)."
    );
}

